import os
from prometheus_client import Gauge, start_http_server
import psycopg2
from psycopg2 import sql
from urllib.parse import urlparse

# Environment variables for database credentials
DB_URL = os.getenv('DATABASE_URL')

# Parse the database URL
parsed_url = urlparse(DB_URL)
db_username = parsed_url.username
db_password = parsed_url.password
db_host = parsed_url.hostname
db_port = parsed_url.port
db_name = parsed_url.path[1:]

# Prometheus gauge metric
db_connection_gauge = Gauge('db_connection_status', 'Database connection status',
                            ['username', 'host', 'connection_string'])

def check_db_connection():
    try:
        # Establish a connection to the database
        conn = psycopg2.connect(dbname=db_name, user=db_username, password=db_password, host=db_host, port=db_port)
        conn.close()
        # Set gauge to 1 if connection is successful
        db_connection_gauge.labels(username='redacted', host=db_host, connection_string='redacted').set(1)
    except Exception as e:
        # Set gauge to 0 if connection fails
        db_connection_gauge.labels(username='redacted', host=db_host, connection_string='redacted').set(0)

if __name__ == '__main__':
    # Start Prometheus client server
    start_http_server(8000)
    while True:
        check_db_connection()